// // This module decrements the 4-bit binary counter on every positive clock edge when the enable signal is low.
module binary_counter_with_enable (
    input clk,
    input reset,
    input enable,
    output reg [3:0] count
);

    always @(posedge clk) begin
        if (reset) begin
            count <= 4'b0000;
        end else if (enable) begin
            count <= count + 1;
        end
    end
endmodule
